import React, { useState, useEffect, useRef, useMemo } from 'react';

const LR = 0.08;
const START_X = 3.0;
const MAX_STEPS = 35;

function computeTrajectory(momentumCoeff) {
  let x = START_X, v = 0;
  const traj = [{ x, v }];
  for (let i = 0; i < MAX_STEPS; i++) {
    const g = 2 * x;
    v = momentumCoeff * v + LR * g;
    x = x - v;
    traj.push({ x, v });
  }
  return traj;
}

const T = {
  bg: '#0a0a0a',
  surface: '#111111',
  card: '#1a1a1a',
  border: '#2a2a2a',
  text: '#fafafa',
  textSec: '#a1a1aa',
  muted: '#3f3f46',
  purple: '#8b5cf6',
  blue: '#38bdf8',
  green: '#a3e635',
  orange: '#fb923c',
  yellow: '#fbbf24',
  gray: '#52525b',
};

function ArrowMarker({ id, color }) {
  return (
    <marker id={id} markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
      <path d="M0,0 L0,6 L6,3 z" fill={color} />
    </marker>
  );
}

export default function App() {
  const [momentum, setMomentum] = useState(0.9);
  const [currentStep, setCurrentStep] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const intervalRef = useRef(null);

  const vanillaTraj = useMemo(() => computeTrajectory(0), []);
  const momentumTraj = useMemo(() => computeTrajectory(momentum), [momentum]);

  const vanillaConverge = useMemo(() => {
    const idx = vanillaTraj.findIndex(s => Math.abs(s.x) < 0.15);
    return idx === -1 ? MAX_STEPS : idx;
  }, [vanillaTraj]);

  const momentumConverge = useMemo(() => {
    const idx = momentumTraj.findIndex(s => Math.abs(s.x) < 0.15);
    return idx === -1 ? MAX_STEPS : idx;
  }, [momentumTraj]);

  useEffect(() => {
    setCurrentStep(0);
    setIsPlaying(false);
  }, [momentum]);

  useEffect(() => {
    if (isPlaying) {
      intervalRef.current = setInterval(() => {
        setCurrentStep(prev => {
          if (prev >= MAX_STEPS) {
            setIsPlaying(false);
            clearInterval(intervalRef.current);
            return prev;
          }
          return prev + 1;
        });
      }, 280);
    } else {
      clearInterval(intervalRef.current);
    }
    return () => clearInterval(intervalRef.current);
  }, [isPlaying]);

  const handleReset = () => {
    setIsPlaying(false);
    clearInterval(intervalRef.current);
    setCurrentStep(0);
  };

  const SVG_W = 560, SVG_H = 220;
  const PL = 42, PR = 16, PT = 18, PB = 32;
  const plotW = SVG_W - PL - PR;
  const plotH = SVG_H - PT - PB;
  const xMin = -3.9, xMax = 3.9;
  const yMaxPlot = 15;

  const toSvg = (x, y) => [
    PL + (x - xMin) / (xMax - xMin) * plotW,
    PT + plotH - (Math.min(y, yMaxPlot) / yMaxPlot) * plotH
  ];

  const parabolaD = useMemo(() => {
    const pts = [];
    for (let xi = xMin; xi <= xMax + 0.01; xi += 0.06) {
      const [sx, sy] = toSvg(xi, xi * xi);
      pts.push(`${xi === xMin || pts.length === 0 ? 'M' : 'L'}${sx.toFixed(1)},${sy.toFixed(1)}`);
    }
    return pts.join(' ');
  }, []);

  const safeV = vanillaTraj[Math.min(currentStep, vanillaTraj.length - 1)];
  const safeM = momentumTraj[Math.min(currentStep, momentumTraj.length - 1)];

  const [vbx, vby] = toSvg(safeV.x, safeV.x * safeV.x);
  const [mbx, mby] = toSvg(safeM.x, safeM.x * safeM.x);

  const velMag = Math.abs(safeM.v);
  const velDir = safeM.v > 0 ? -1 : 1;
  const arrowLen = Math.min(velMag * 28, 48);
  const arrowEndX = mbx + velDir * arrowLen;
  const [, arrowEndY] = toSvg(safeM.x - safeM.v * 0.6, (safeM.x - safeM.v * 0.6) ** 2);

  const vTrail = vanillaTraj.slice(0, currentStep + 1);
  const mTrail = momentumTraj.slice(0, currentStep + 1);

  const yGridLines = [0, 3, 6, 9, 12];
  const xGridLines = [-3, -2, -1, 0, 1, 2, 3];

  const [minX, minY] = toSvg(0, 0);

  const faster = momentumConverge < vanillaConverge;
  const steps2conv = momentumConverge;
  const vSteps2conv = vanillaConverge;

  const velocityPct = Math.round(Math.abs(safeM.v) * 100) / 100;
  const currentLoss = Math.round(safeM.x * safeM.x * 1000) / 1000;
  const currentParam = Math.round(safeM.x * 1000) / 1000;

  return (
    <div style={{ fontFamily: "'JetBrains Mono', monospace", background: T.bg, minHeight: '100vh', padding: '14px', boxSizing: 'border-box', color: T.text }}>
      <div style={{ maxWidth: 600, margin: '0 auto' }}>

        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
          <div>
            <div style={{ fontSize: 17, fontWeight: 700, letterSpacing: '-0.3px' }}>Momentum Optimizer</div>
            <div style={{ fontSize: 10, color: T.textSec, marginTop: 2 }}>Loss: f(x) = x^2 &nbsp;|&nbsp; LR = {LR} &nbsp;|&nbsp; Start: x = {START_X}</div>
          </div>
          <div style={{ display: 'flex', gap: 6 }}>
            <button
              onClick={() => setIsPlaying(p => !p)}
              style={{ background: T.purple, border: 'none', borderRadius: 6, color: '#fff', padding: '6px 14px', cursor: 'pointer', fontSize: 11, fontFamily: 'inherit', fontWeight: 600 }}
            >
              {isPlaying ? 'Pause' : 'Play'}
            </button>
            <button
              onClick={handleReset}
              style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 6, color: T.textSec, padding: '6px 12px', cursor: 'pointer', fontSize: 11, fontFamily: 'inherit' }}
            >
              Reset
            </button>
          </div>
        </div>

        {/* Legend */}
        <div style={{ display: 'flex', gap: 16, marginBottom: 8, paddingLeft: 4 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
            <div style={{ width: 20, height: 3, background: T.gray, borderRadius: 2 }} />
            <span style={{ fontSize: 10, color: T.textSec }}>Vanilla GD (momentum = 0)</span>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
            <div style={{ width: 20, height: 3, background: T.purple, borderRadius: 2 }} />
            <span style={{ fontSize: 10, color: T.textSec }}>Momentum = {momentum}</span>
          </div>
        </div>

        {/* SVG Visualization */}
        <div style={{ background: T.surface, borderRadius: 10, border: `1px solid ${T.border}`, padding: '6px 10px 4px', marginBottom: 10 }}>
          <svg width="100%" viewBox={`0 0 ${SVG_W} ${SVG_H}`} style={{ display: 'block' }}>
            <defs>
              <ArrowMarker id="arr-purple" color={T.purple} />
              <ArrowMarker id="arr-gray" color={T.gray} />
            </defs>

            {/* Grid */}
            {yGridLines.map(yv => {
              const [, sy] = toSvg(0, yv);
              return (
                <g key={yv}>
                  <line x1={PL} x2={PL + plotW} y1={sy} y2={sy} stroke={T.muted} strokeWidth="0.5" strokeDasharray="4,4" />
                  <text x={PL - 4} y={sy + 3} textAnchor="end" fill={T.gray} fontSize="8">{yv}</text>
                </g>
              );
            })}
            {xGridLines.map(xv => {
              const [sx] = toSvg(xv, 0);
              const [, sy] = toSvg(0, 0);
              return (
                <g key={xv}>
                  <line x1={sx} x2={sx} y1={PT} y2={PT + plotH} stroke={T.muted} strokeWidth="0.5" strokeDasharray="4,4" />
                  <text x={sx} y={PT + plotH + 12} textAnchor="middle" fill={T.gray} fontSize="8">{xv}</text>
                </g>
              );
            })}

            {/* Axes */}
            <line x1={PL} x2={PL + plotW} y1={PT + plotH} y2={PT + plotH} stroke={T.border} strokeWidth="1" />
            <line x1={PL} x2={PL} y1={PT} y2={PT + plotH} stroke={T.border} strokeWidth="1" />

            {/* Axis labels */}
            <text x={PL + plotW / 2} y={SVG_H - 2} textAnchor="middle" fill={T.textSec} fontSize="9">parameter x</text>
            <text x={9} y={PT + plotH / 2} textAnchor="middle" fill={T.textSec} fontSize="9" transform={`rotate(-90, 9, ${PT + plotH / 2})`}>loss</text>

            {/* Parabola */}
            <path d={parabolaD} fill="none" stroke="#4a4a5a" strokeWidth="2" strokeLinecap="round" />

            {/* Minimum marker */}
            <circle cx={minX} cy={minY} r={4} fill={T.green} opacity={0.85} />
            <text x={minX + 6} y={minY - 5} fill={T.green} fontSize={8} fontWeight="600">minimum</text>

            {/* Vanilla trail */}
            {vTrail.length > 1 && vTrail.map((s, i) => {
              if (i === 0) return null;
              const [ax, ay] = toSvg(vTrail[i - 1].x, vTrail[i - 1].x * vTrail[i - 1].x);
              const [bx, by] = toSvg(s.x, s.x * s.x);
              return <line key={i} x1={ax} y1={ay} x2={bx} y2={by} stroke={T.gray} strokeWidth="1.5" strokeOpacity={0.5} />;
            })}
            {vTrail.map((s, i) => {
              const [sx, sy] = toSvg(s.x, s.x * s.x);
              if (i === vTrail.length - 1) return null;
              return <circle key={i} cx={sx} cy={sy} r={2} fill={T.gray} opacity={0.4} />;
            })}

            {/* Momentum trail */}
            {mTrail.length > 1 && mTrail.map((s, i) => {
              if (i === 0) return null;
              const [ax, ay] = toSvg(mTrail[i - 1].x, mTrail[i - 1].x * mTrail[i - 1].x);
              const [bx, by] = toSvg(s.x, s.x * s.x);
              const alpha = 0.3 + 0.7 * (i / mTrail.length);
              return <line key={i} x1={ax} y1={ay} x2={bx} y2={by} stroke={T.purple} strokeWidth="2" strokeOpacity={alpha} />;
            })}
            {mTrail.map((s, i) => {
              const [sx, sy] = toSvg(s.x, s.x * s.x);
              if (i === mTrail.length - 1) return null;
              return <circle key={i} cx={sx} cy={sy} r={2.5} fill={T.purple} opacity={0.35} />;
            })}

            {/* Velocity arrow on momentum ball */}
            {currentStep > 0 && arrowLen > 3 && (
              <line
                x1={mbx} y1={mby}
                x2={arrowEndX} y2={arrowEndY}
                stroke={T.orange}
                strokeWidth="2"
                markerEnd="url(#arr-purple)"
                opacity={0.9}
              />
            )}

            {/* Vanilla ball */}
            <circle cx={vbx} cy={vby} r={6} fill={T.gray} stroke="#71717a" strokeWidth="1.5" />

            {/* Momentum ball */}
            <circle cx={mbx} cy={mby} r={8} fill={T.purple} stroke="#a78bfa" strokeWidth="2"
              style={{ filter: 'drop-shadow(0 0 5px #8b5cf666)' }}
            />

            {/* Step counter in viz */}
            <text x={PL + plotW - 2} y={PT + 12} textAnchor="end" fill={T.textSec} fontSize={9}>step {currentStep}</text>
          </svg>
        </div>

        {/* Momentum Slider */}
        <div style={{ background: T.surface, border: `1px solid ${T.border}`, borderRadius: 10, padding: '10px 14px', marginBottom: 10 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 }}>
            <span style={{ fontSize: 11, color: T.textSec }}>Momentum coefficient</span>
            <span style={{ fontSize: 14, color: T.purple, fontWeight: 700 }}>{momentum}</span>
          </div>
          <input
            type="range"
            min="0"
            max="0.97"
            step="0.01"
            value={momentum}
            onChange={e => setMomentum(parseFloat(e.target.value))}
            style={{ width: '100%', accentColor: T.purple, cursor: 'pointer' }}
          />
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9, color: T.gray, marginTop: 2 }}>
            <span>0 (vanilla GD)</span>
            <span>0.5 (moderate)</span>
            <span>0.97 (high)</span>
          </div>
        </div>

        {/* Stats row */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr 1fr', gap: 6, marginBottom: 10 }}>
          {[
            { label: 'x (param)', value: currentParam, color: T.purple },
            { label: 'loss f(x)', value: currentLoss, color: T.yellow },
            { label: 'velocity |v|', value: velocityPct, color: T.orange },
            { label: 'steps to conv', value: steps2conv === MAX_STEPS ? '35+' : steps2conv, color: faster ? T.green : T.textSec },
          ].map(({ label, value, color }) => (
            <div key={label} style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 8, padding: '8px 10px' }}>
              <div style={{ fontSize: 9, color: T.gray, marginBottom: 3 }}>{label}</div>
              <div style={{ fontSize: 13, color, fontWeight: 700 }}>{value}</div>
            </div>
          ))}
        </div>

        {/* Insight */}
        <div style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 10, padding: '10px 14px' }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: T.green, marginBottom: 5 }}>Key Insight</div>
          {momentum === 0 ? (
            <div style={{ fontSize: 11, color: T.textSec, lineHeight: 1.6 }}>
              Momentum = 0 means <span style={{ color: T.text }}>pure gradient descent</span>. Each step uses only the current gradient - both balls move identically. The update rule is simply: <span style={{ color: T.yellow }}>param = param - lr * grad</span>.
            </div>
          ) : momentum < 0.5 ? (
            <div style={{ fontSize: 11, color: T.textSec, lineHeight: 1.6 }}>
              Low momentum ({momentum}): velocity builds <span style={{ color: T.purple }}>slowly</span>. The purple ball is slightly faster than vanilla GD. Velocity = {momentum} x previous_v + {LR} x grad, accumulating history over time.
            </div>
          ) : momentum < 0.85 ? (
            <div style={{ fontSize: 11, color: T.textSec, lineHeight: 1.6 }}>
              Momentum = {momentum}: the purple ball <span style={{ color: T.purple }}>builds speed</span> as gradients push in the same direction. It converges in <span style={{ color: T.green }}>{steps2conv === MAX_STEPS ? '35+' : steps2conv} steps</span> vs vanilla's <span style={{ color: T.gray }}>{vSteps2conv === MAX_STEPS ? '35+' : vSteps2conv}</span> - like a ball rolling downhill gaining momentum.
            </div>
          ) : momentum < 0.95 ? (
            <div style={{ fontSize: 11, color: T.textSec, lineHeight: 1.6 }}>
              High momentum ({momentum}): velocity builds quickly, <span style={{ color: T.orange }}>overshooting</span> the minimum then correcting. The orange arrow shows velocity magnitude. Despite oscillation, it converges in <span style={{ color: T.green }}>{steps2conv === MAX_STEPS ? '35+' : steps2conv} steps</span> - much faster than vanilla ({vSteps2conv === MAX_STEPS ? '35+' : vSteps2conv} steps).
            </div>
          ) : (
            <div style={{ fontSize: 11, color: T.textSec, lineHeight: 1.6 }}>
              Very high momentum ({momentum}): the ball <span style={{ color: T.orange }}>overshoots and oscillates</span> significantly. Too much history causes instability. In real training, momentum is tuned to balance speed vs stability - typically 0.9 works best.
            </div>
          )}
        </div>

        {/* Formula */}
        <div style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 10, padding: '8px 14px', marginTop: 8 }}>
          <div style={{ fontSize: 9, color: T.gray, marginBottom: 5 }}>Update equations (applied each step)</div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
            <div style={{ fontSize: 11, color: T.textSec }}>
              <span style={{ color: T.orange }}>v</span> = <span style={{ color: T.purple }}>{momentum}</span> x <span style={{ color: T.orange }}>v_prev</span> + <span style={{ color: T.blue }}>{LR}</span> x <span style={{ color: T.yellow }}>grad</span>
              &nbsp;&nbsp;
              <span style={{ color: T.muted }}>// = {Math.round(momentum * safeM.v * 100) / 100} + {Math.round(LR * 2 * safeM.x * 100) / 100} = {Math.round((momentum * safeM.v + LR * 2 * safeM.x) * 1000) / 1000}</span>
            </div>
            <div style={{ fontSize: 11, color: T.textSec }}>
              <span style={{ color: T.text }}>x</span> = <span style={{ color: T.text }}>x</span> - <span style={{ color: T.orange }}>v</span>
              &nbsp;&nbsp;
              <span style={{ color: T.muted }}>// = {currentParam} - {velocityPct} = {Math.round((safeM.x - (momentum * safeM.v + LR * 2 * safeM.x)) * 1000) / 1000}</span>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}
